        head.position.y = 1.65;
        group.add(head);

        // Hood
        const hood = new THREE.Mesh(new THREE.ConeGeometry(0.2, 0.25, 44), robeMat);
        hood.position.y = 1.78;
        group.add(hood);

        // Purple eyes
