        // Slit pupil
        const pupil = new THREE.Mesh(new THREE.BoxGeometry(0.02, 0.12, 0.02), new THREE.MeshStandardMaterial({ color: 0x000000 }));
        pupil.position.set(0, 1.75, 0.47);
